export const _formatNormalizedSet: Set<string> = new Set<string>();

// @kern-source: engine-registry:140
export const _OPENAI_COMPAT_ONLY_HOST_SUFFIXES: string[] = [ 'api.kimi.com', 'moonshot.cn', 'moonshot.ai', 'api.groq.com', 'together.xyz', 'together.ai', 'api.deepinfra.com', 'openrouter.ai', 'api.deepseek.com', 'api.perplexity.ai' ];

/**
 * Narrow normalization: if api.format='anthropic' but the baseUrl host is on the known-OpenAI-compat-only allowlist (Kimi/Moonshot, Groq, Together, DeepInfra, OpenRouter), rewrite to 'openai'. Every other non-Anthropic host is left alone — arbitrary Anthropic-compatible proxies are valid configurations and must not be silently coerced. Skips /coding/ API paths which are specialised endpoints that choose their own wire format. Mutates raw in place; logs once per engine id.
 */
// @kern-source: engine-registry:142
function normalizeEngineFormat(raw: any, fileLabel: string): void {
  const api = raw?.api;
  if (!api || api.format !== 'anthropic' || typeof api.baseUrl !== 'string') return;
  let parsedUrl: URL;
  try { parsedUrl = new URL(api.baseUrl); } catch { return; }
  const host = parsedUrl.host.toLowerCase();
  if (host === 'api.anthropic.com' || host.endsWith('.anthropic.com')) return;
  // Skip specialised /coding/ API paths — these are provider-specific endpoints
  // (e.g. api.kimi.com/coding/v1, api.z.ai/api/coding/paas/v4) that declare their
  // own wire format and should not be force-rewritten based on hostname alone.
  if (parsedUrl.pathname.toLowerCase().includes('/coding/')) return;
  const matched = _OPENAI_COMPAT_ONLY_HOST_SUFFIXES.some((suffix: string) => host === suffix || host.endsWith('.' + suffix));
  if (!matched) return;
  api.format = 'openai';
  const key = typeof raw.id === 'string' ? raw.id : fileLabel;
  if (!_formatNormalizedSet.has(key)) {
    _formatNormalizedSet.add(key);
    console.log(`[agon] engine '${key}': api.format 'anthropic' on known OpenAI-compat host '${host}' normalized to 'openai'.`);
  }
}

