    if (!id) return [];
    if (ids.includes(id)) return [id];
    const needle = id.trim().toLowerCase();
    if (!needle) return [];
    const ci = ids.filter((k) => k.toLowerCase() === needle);
    if (ci.length > 0) return ci;
    const prefix = ids.filter((k) => k.toLowerCase().startsWith(needle));
    if (prefix.length > 0) return prefix;
    const substr = ids.filter((k) => k.toLowerCase().includes(needle));
    if (substr.length > 0) return substr;
    return [id];
